import React, { useEffect, useRef, useState } from 'react';
import { useGame } from '../context/GameContext';
import { rollTitles, buildLegend, getCareerWindows } from '../utils/gameLogic';
import './RetirementScreen.css';

function Confetti() {
  const colors = ['#C9A84C','#E8C97A','#fff','#2ECC71','#3498DB','#E74C3C'];
  return (
    <div className="confetti-layer" aria-hidden>
      {Array.from({ length: 22 }, (_, i) => (
        <div
          key={i}
          className="confetti-piece"
          style={{
            left: `${5 + Math.random() * 90}%`,
            top:  `${Math.random() * 80}%`,
            background: colors[i % colors.length],
            animationDelay: `${Math.random() * 0.6}s`,
            animationDuration: `${0.8 + Math.random() * 0.8}s`,
          }}
        />
      ))}
    </div>
  );
}

function AnimBar({ value, max, color, delay }) {
  const ref = useRef(null);
  useEffect(() => {
    const t = setTimeout(() => {
      if (ref.current) ref.current.style.width = `${Math.min(100, Math.round(value / max * 100))}%`;
    }, delay);
    return () => clearTimeout(t);
  }, [value, max, delay]);
  return (
    <div className="ls-bar-wrap">
      <div ref={ref} className="ls-bar" style={{ background: color }} />
    </div>
  );
}

export default function RetirementScreen() {
  const { state, dispatch } = useGame();
  const { player, totals, career } = state;

  const [phase, setPhase]       = useState('intro');    // intro | titles | legend
  const [titles, setTitles]     = useState([]);
  const [revealed, setRevealed] = useState([]);
  const [legend, setLegend]     = useState(null);
  const [showConfetti, setShowConfetti] = useState(false);

  const windows = getCareerWindows(player.birthYear);
  const clubs   = [...new Set(career.map(p => p.club?.name).filter(Boolean))];

  useEffect(() => {
    // Inicia a sequência
    setTimeout(() => setPhase('titles'), 800);
  }, []);

  useEffect(() => {
    if (phase !== 'titles') return;
    const rolled = rollTitles(career, player.potential);
    setTitles(rolled);

    rolled.forEach((t, i) => {
      setTimeout(() => {
        setRevealed(prev => [...prev, i]);
        if (t.won > 0 && (t.id === 'bola' || t.id === 'mundial')) {
          setShowConfetti(true);
          setTimeout(() => setShowConfetti(false), 1500);
        }
      }, 600 + i * 900);
    });

    const legendDelay = 600 + rolled.length * 900 + 700;
    setTimeout(() => {
      const leg = buildLegend(rolled, totals, player.potential);
      setLegend(leg);
      dispatch({ type: 'SET_TITLES', payload: { titles: rolled, legend: leg } });
      setPhase('legend');
    }, legendDelay);
  }, [phase]);

  return (
    <div className="ret-wrap">
      {showConfetti && <Confetti />}

      {/* Hero */}
      <div className="ret-hero fade-up">
        <div className="ret-eyebrow">Aposentadoria · {player.birthYear + 35} anos</div>
        <div className="ret-name">{player.name} <span>{player.nationality && player.flag}</span></div>
        <div className="ret-years">
          {player.birthYear + 18} — {player.birthYear + 35} · {player.positionLabel} · {player.flag} {player.nationality}
        </div>
        <div className="ret-clubs">
          {clubs.map(c => <span className="ret-club-chip" key={c}>{c}</span>)}
        </div>
      </div>

      {/* Totais */}
      <div className="ret-totals fade-up">
        {[
          { label: 'Jogos',    val: totals.jogos },
          { label: 'Gols',     val: totals.gols },
          { label: 'Assist.',  val: totals.assist },
          { label: 'Clubes',   val: clubs.length },
        ].map(t => (
          <div className="ret-total-item" key={t.label}>
            <div className="ret-total-num">{t.val}</div>
            <div className="ret-total-label">{t.label}</div>
          </div>
        ))}
      </div>

      {/* Títulos */}
      <div className="ret-section-label">Roleta de títulos</div>
      <div className="titles-drum">
        {phase === 'intro' && (
          <div className="titles-loading">
            <div className="tl-dot" /><div className="tl-dot" /><div className="tl-dot" />
            <span>Sorteando títulos da carreira...</span>
          </div>
        )}

        {titles.map((t, i) => {
          const isRevealed = revealed.includes(i);
          const won        = t.won > 0;
          return (
            <div
              key={t.id}
              className={`title-slot ${!isRevealed ? 'pending' : won ? 'won' : 'lost'}`}
            >
              <div className="title-icon">
                {!isRevealed ? '⬜' : isRevealed && i === revealed[revealed.length - 1] ? '⏳' : t.icon}
              </div>
              <div className="title-info">
                <div className="title-name">{t.name}</div>
                <div className="title-detail">{t.detail}</div>
              </div>
              <div className="title-count">
                {!isRevealed ? '?' : t.won}
              </div>
              {won && isRevealed && <div className="title-shine" />}
            </div>
          );
        })}
      </div>

      {/* Legado */}
      {legend && phase === 'legend' && (
        <div className="legend-card pop-in">
          <div className="legend-header">
            <div className="legend-trophy">{legend.trophy}</div>
            <div className="legend-info">
              <div className="legend-rank">{legend.rank}</div>
              <div className="legend-title">{legend.title}</div>
              <div className="legend-sub">{legend.sub}</div>
            </div>
          </div>
          <div className="legend-bars">
            {[
              { label: 'Gols na carreira', val: totals.gols,    max: 400, color: 'var(--gold)' },
              { label: 'Assistências',     val: totals.assist,  max: 200, color: 'var(--blue)' },
              { label: 'Jogos',            val: totals.jogos,   max: 800, color: 'var(--green)' },
              { label: 'Títulos',          val: titles.reduce((s,t) => s + t.won, 0), max: 20, color: 'var(--purple)' },
            ].map((b, i) => (
              <div className="ls-row" key={b.label}>
                <span className="ls-label">{b.label}</span>
                <AnimBar value={b.val} max={b.max} color={b.color} delay={400 + i * 150} />
                <span className="ls-val">{b.val}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {phase === 'legend' && (
        <button
          className="restart-btn pop-in"
          onClick={() => dispatch({ type: 'RESET' })}
        >
          <i className="ti ti-refresh" />
          Nova carreira
        </button>
      )}
    </div>
  );
}
